'use client';

import { type MouseEvent, useEffect, useState } from 'react';

import { useRouter } from 'next/navigation';

import { useConnectModal } from '@rainbow-me/rainbowkit';
import { differenceInDays, differenceInHours, format, parseISO } from 'date-fns';
import { useDispatch, useSelector } from 'react-redux';
import { useAccount } from 'wagmi';

import { useToast } from '@/components/ToastSystem/hooks/useToast';

import useWallet from '@/hooks/useWallet';

import { parseDateSafely } from '@/utils/dateFormatters';
import { formatNumber, toNumber } from '@/utils/decimalHelpers';

import { ALLOWED_CHAIN_DISPLAY_NAME, ALLOWED_CHAIN_ID } from '@/config/wagmiConfig';
import { MONTHS } from '@/constants/dates';
import { getUserProfile } from '@/store/slices/authSlice';
import { fetchLoans, getUserLoans, updateLoanStatus } from '@/store/slices/loanSlice';
import type { AppDispatch, RootState } from '@/store/store';
import { type User } from '@/types/authTypes';
import { ERROR_CODES } from '@/types/errorCodes';
import { getToastKeyFromErrorCode } from '@/types/errorToastMapping';
import type { Loan } from '@/types/loanTypes';

export default function UserCard(loan: Loan) {
   const loanData = loan;
   const borrowerUser = loanData.borrowerUser || '';

   const router = useRouter();
   const dispatch = useDispatch<AppDispatch>();
   const { Transfer } = useWallet();
   const account = useAccount();
   const { isConnected } = account;
   const { openConnectModal } = useConnectModal();
   const [showModal, setShowModal] = useState(false);
   const [isProcessing, setIsProcessing] = useState(false);
   const { showToastByConfig } = useToast();
   const wallet = useSelector((state: RootState) => state.auth.user?.walletAddress);
   const username = useSelector((state: RootState) => state.auth.username);

   const [localProfile, setLocalProfile] = useState<User | null>(null);
   const [localTotalRepaid, setLocalTotalRepaid] = useState(0);

   const time = parseDateSafely(loanData.createdAt).toISOString();
   const splt = time.split('T')[0].split('-');

   const due = parseISO(loanData.dueDate);
   const now = new Date();
   const formattedDate = format(due, 'MMMM d, yyyy');

   function plural(value: number, unit: string) {
      return `${value} ${unit}${value === 1 ? '' : 's'} left`;
   }
   const daysLeft = differenceInDays(due, now);
   let timeLeftLabel = '';
   if (daysLeft >= 1) {
      timeLeftLabel = plural(daysLeft, 'Day');
   } else {
      let hoursLeft = differenceInHours(due, now);
      if (hoursLeft < 0) hoursLeft = 0;
      timeLeftLabel = plural(hoursLeft, 'Hour');
   }

   useEffect(() => {
      let mounted = true;
      const fetch = async () => {
         try {
            const profileRes = await dispatch(getUserProfile(borrowerUser)).unwrap();
            const profileObj = profileRes?.user || profileRes;
            if (mounted) setLocalProfile(profileObj);
         } catch (error) {
            console.error('Error fetching profile:', (error as Error).message || error);
         }

         try {
            const loansRes = await dispatch(getUserLoans(borrowerUser)).unwrap();
            const loansArray = loansRes?.gloans || loansRes?.loans || loansRes || [];
            if (mounted) {
               const repaid = (loansArray || []).reduce(
                  (sum: number, ln: Loan) => (ln.repaymentStatus === 'Paid' ? sum + toNumber(ln.loanAmount) : sum),
                  0
               );
               setLocalTotalRepaid(repaid);
            }
         } catch (error: unknown) {
            console.error('Error fetching loans:', (error as Error).message || error);
         }
      };

      fetch();
      return () => {
         mounted = false;
      };
   }, [dispatch, borrowerUser]);

   const handleFetch = async () => {
      setShowModal(false);
      await dispatch(fetchLoans())
         .unwrap()
         .then(() => {
            console.log('Loan fetched successfully');
         })
         .catch((error: Error) => {
            console.error('Error fetching loan:', error.message || error);
         });
   };

   const handleLend = async (e: MouseEvent<HTMLButtonElement>) => {
      e.preventDefault();

      if (isProcessing) {
         return;
      }

      if (!isConnected) {
         openConnectModal?.();
         e.stopPropagation();
         return;
      }

      console.log('[handleLend] wallet state', {
         reduxWallet: wallet,
         wagmiAddress: account.address,
         isConnected,
         loanWallet: loanData.borrowerWallet,
         loanCoin: loanData.coin,
         allowedChain: ALLOWED_CHAIN_DISPLAY_NAME,
         currentChainId: account.chain?.id,
         currentChainName: account.chain?.name
      });

      if (loanData.borrowerUser === username) {
         showToastByConfig(getToastKeyFromErrorCode(ERROR_CODES.LOAN_SELF_LENDING_NOT_ALLOWED));
         e.stopPropagation();
         return;
      }

      const lenderWallet = account.address?.trim() || wallet?.trim();
      if (!lenderWallet) {
         showToastByConfig(getToastKeyFromErrorCode(ERROR_CODES.WALLET_MISSING));
         e.stopPropagation();
         return;
      }

      const borrowerWallet = loanData.borrowerWallet?.trim();
      if (!borrowerWallet) {
         showToastByConfig(getToastKeyFromErrorCode(ERROR_CODES.WALLET_MISSING));
         e.stopPropagation();
         return;
      }

      if (account.chain?.id !== ALLOWED_CHAIN_ID) {
         showToastByConfig(getToastKeyFromErrorCode(ERROR_CODES.NETWORK_REQUIRED));
         e.stopPropagation();
         return;
      }

      const transferCoin = loanData.coin?.trim() || 'USDC';

      setIsProcessing(true);

      try {
         const transactionHash = await Transfer(e, borrowerWallet, formatNumber(loanData.loanAmount), loanData.id, transferCoin);

         if (transactionHash) {
            try {
               const loanPayload = {
                  id: loanData.id,
                  wallet: lenderWallet,
                  username,
                  loanStatus: 'Lent',
                  hash: transactionHash
               };

               await dispatch(updateLoanStatus(loanPayload)).unwrap();
               setShowModal(true);
            } catch (updateError: unknown) {
               const errorMessage = updateError instanceof Error ? updateError.message : 'Unknown error';
               console.error('[CRITICAL] Lending transaction succeeded but database update failed:', errorMessage);
               console.error(
                  '[RECONCILIATION REQUIRED] Loan ID:',
                  loanData.id,
                  '| Amount:',
                  loanData.loanAmount,
                  '| Lender:',
                  username,
                  '| Hash:',
                  transactionHash
               );
               showToastByConfig(getToastKeyFromErrorCode(ERROR_CODES.TRANSACTION_FAILED));
            }
         }
      } catch (transferError: unknown) {
         const errorMessage = transferError instanceof Error ? transferError.message : 'Unknown error';
         console.error('Transfer failed:', errorMessage);
         showToastByConfig(getToastKeyFromErrorCode(ERROR_CODES.TRANSACTION_FAILED));
      } finally {
         setIsProcessing(false);
      }
   };

   const loanReason = loanData.reason?.trim() ? loanData.reason.trim() : 'Unknown Reason';

   return (
      <>
         <div
            className="rounded-xl border border-solid border-gray-200 shadow-lg overflow-hidden flex flex-col justify-between"
            style={{ fontFamily: 'Inter, sans-serif' }}
         >
            <div className="bg-white p-5 rounded-t-xl">
               <div className="flex justify-between items-start">
                  <h2 className="text-navy-900 text-[15px] font-semibold leading-5 text-[#0B1033] truncate">{loanReason}</h2>
               </div>
               <div className="flex justify-between items-center mt-2">
                  <p className="text-[13px] font-normal text-[#0B1033]">
                     by{' '}
                     <a
                        onClick={() => router.push('/user/' + loanData.borrowerUser)}
                        className="text-[#0B1033] underline hover:no-underline"
                     >
                        {loanData.borrowerUser?.slice(0, 12)}
                     </a>
                  </p>
                  <p className="text-[13px] font-semibold text-[#6B6B7B]">{MONTHS[parseInt(splt[1])] + ' ' + splt[2] + ', ' + splt[0]}</p>
               </div>
            </div>

            <div className="bg-[#E6F9E9] text-[#2F7A3E] text-[13px] font-normal flex items-center justify-center gap-2 px-5 py-2 border-solid border-b border-[#D9EED9]">
               <i className="fas fa-lock text-[14px]"></i>
               <span>${localProfile?.cs || '0'} Maximum Credit</span>
            </div>

            <div className="bg-white px-6 py-4 border-solid border-b border-[#D9D9D9]">
               <div className="flex items-center justify-between gap-12 text-left">
                  <div className="flex items-center justify-center gap-4">
                     <div className="flex flex-col items-start">
                        <p className="text-xs font-normal text-[#6B6B7B]">Asking</p>
                        <p className="text-lg font-normal text-[#0B1033]">${formatNumber(loanData.loanAmount)}</p>
                     </div>
                     <div className="border-s border-gray-400 w-px h-16 rotate-12"></div>
                     <div className="flex flex-col items-start">
                        <p className="text-xs font-normal text-[#6B6B7B]">Payback</p>
                        <p className="text-lg font-normal text-[#2F7A3E]">${formatNumber(loanData.totalRepaymentAmount)}</p>
                     </div>
                  </div>
                  <div className="flex flex-col gap-0.5">
                     <p className="text-sm font-normal text-[#6B6B7B]">Due Date</p>
                     <p className="text-xl font-semibold text-[#D92D2D]">{timeLeftLabel}</p>
                     <p className="text-xs font-normal text-[#0B1033]">on {formattedDate}</p>
                  </div>
               </div>
            </div>

            <div className="flex justify-between items-center px-5 py-3 bg-white">
               <p className="text-sm font-normal text-[#0B1033]">Borrower Details</p>
               <button
                  onClick={() => router.push('/user/' + loanData.borrowerUser)}
                  type="button"
                  className="flex items-center gap-1 bg-[#2563EB] text-white text-sm font-semibold px-4 py-1 rounded-md hover:bg-[#1e4bb8] transition"
               >
                  Insights
                  <i className="fas fa-external-link-alt text-[12px]"></i>
               </button>
            </div>

            <div className="flex text-center text-[15px] font-semibold">
               <div className="flex-1 bg-[#D9EEFF] py-4">
                  <p className="text-[#2563EB] font-normal">Repaid</p>
                  <p className="text-[#2563EB] text-[28px] font-bold mt-1">{formatNumber(localTotalRepaid)}</p>
               </div>
               <div className="flex-1 bg-[#FFE9C9] py-4">
                  <p className="text-[#FBBF24] font-normal">Active</p>
                  <p className="text-[#FBBF24] text-[28px] font-bold mt-1">{localProfile?.nal ?? 0}</p>
               </div>
               <div className="flex-1 bg-[#FFE9E9] py-4">
                  <p className="text-[#D92D2D] font-normal">Default</p>
                  <p className="text-[#D92D2D] text-[28px] font-bold mt-1">0</p>
               </div>
            </div>

            <div className="flex items-center justify-center gap-2 text-[#2563EB] text-xs font-semibold py-3 bg-[#F0F7FF] mt-4">
               <i className="fas fa-info-circle text-sm"></i>
               <span>GOOD STANDING</span>
            </div>

            {loanData.borrowerUser === username ? (
               <div className="p-5 bg-gray-100">
                  <div className="w-full bg-gray-300 text-gray-600 font-semibold text-[15px] py-3 rounded-lg text-center cursor-not-allowed">
                     Your Loan Request
                  </div>
               </div>
            ) : (
               <div className="p-5 bg-white">
                  <button
                     onClick={handleLend}
                     disabled={isProcessing}
                     type="button"
                     className="w-full bg-[#2563EB] text-white font-semibold text-[15px] py-3 rounded-lg hover:bg-[#1e4bb8] transition disabled:opacity-50 disabled:cursor-not-allowed"
                  >
                     {isProcessing ? 'Processing...' : 'Send Your Help'}
                  </button>
               </div>
            )}
         </div>

         {showModal ? (
            <div className="fixed inset-0 z-50 flex items-center justify-center bg-black bg-opacity-50">
               <section className="bg-white rounded-lg shadow-md max-w-md mx-auto flex flex-col" style={{ minWidth: '320px' }}>
                  <header
                     className="rounded-t-lg px-6 py-4 flex items-center justify-between"
                     style={{ background: 'linear-gradient(90deg, #C55FFF 0%, #7B5FFF 100%)' }}
                  >
                     <h3 className="text-white font-extrabold text-lg">Funded</h3>
                     <button
                        onClick={() => handleFetch()}
                        aria-label="Close"
                        className="bg-white rounded-md px-2 py-1 text-[#7B5FFF] font-extrabold text-lg leading-none focus:outline-none"
                        type="button"
                     >
                        X
                     </button>
                  </header>
                  <div className="p-6 flex flex-col gap-4 text-center text-gray-900 text-sm font-semibold relative">
                     <p className="font-extrabold text-base leading-5">{loan.reason}</p>
                     <p className="text-xs font-normal">
                        Thank you for supporting&nbsp;
                        <a
                           onClick={() => router.push('/user/' + loanData.borrowerUser)}
                           className="text-[#1E56FF] font-extrabold underline"
                           href="#"
                        >
                           {loan.borrowerUser}
                        </a>
                     </p>
                     <svg
                        width="242"
                        height="253"
                        viewBox="0 0 242 253"
                        fill="none"
                        xmlns="http://www.w3.org/2000/svg"
                        xmlnsXlink="http://www.w3.org/1999/xlink"
                     >
                        <rect width="242" height="253" fill="url(#pattern0_304_723)" fill-opacity="0.4" />
                        <defs>
                           <pattern id="pattern0_304_723" patternContentUnits="objectBoundingBox" width="1" height="1">
                              <use xlinkHref="#image0_304_723" transform="matrix(0.00228467 0 0 0.00218576 -0.0154593 -0.0562771)" />
                           </pattern>
                           <image
                              id="image0_304_723"
                              width="475"
                              height="509"
                              preserveAspectRatio="none"
                              xlinkHref="data:image/png;base64,"
                           />
                        </defs>
                     </svg>
                     <dl className="text-left w-full max-w-xs mx-auto grid grid-cols-2 gap-y-1 gap-x-2 text-sm font-semibold">
                        <dt className="text-gray-900">Network:</dt>
                        <dd className="text-gray-900 text-right font-extrabold">{ALLOWED_CHAIN_DISPLAY_NAME}</dd>
                        <dt className="text-gray-900">Amount Funded:</dt>
                        <dd className="text-gray-900 text-right font-extrabold">${formatNumber(loan.loanAmount)}</dd>
                        <dt className="text-gray-900">Expected Return:</dt>
                        <dd className="text-green-700 text-right font-extrabold">${formatNumber(loanData.totalRepaymentAmount)}</dd>
                        <dt className="text-gray-900">Return Date:</dt>
                        <dd className="text-gray-900 text-right font-extrabold">{formattedDate}</dd>
                     </dl>
                     <p className="text-xs font-normal mt-4">
                        Have any questions?&nbsp;
                        <a className="italic font-semibold underline text-[#1E56FF]" href="#">
                           Contact Support
                        </a>
                     </p>
                     <button
                        onClick={() => router.push('/profile')}
                        className="bg-[#1E56FF] text-white font-extrabold text-sm rounded-md py-3 mt-4 w-full"
                        type="button"
                     >
                        Review Funding
                     </button>
                  </div>
               </section>
            </div>
         ) : null}
      </>
   );
}
